import re
import json

def detect_sections(resume_text, dataset):
    lines = resume_text.split('\n')
    detected = []
    sections = dataset['sections']
    quick_index = dataset['quick_lookup_index']

    for i, line in enumerate(lines):
        stripped = line.strip()
        if not stripped or len(stripped) > 80:
            continue
        if len(stripped.split()) > 8:
            continue

        confidence = 0.0
        matched_section = None

        # Quick lookup
        lower = stripped.lower().rstrip(':').strip()
        if lower in quick_index:
            matched_section = quick_index[lower]
            confidence = 1.0

        # Regex matching
        if not matched_section:
            for section_key, section_data in sections.items():
                pattern = section_data['regex_pattern']
                if re.match(pattern, stripped, re.IGNORECASE | re.MULTILINE):
                    matched_section = section_key
                    confidence = 0.92
                    break

        # Formatting boosts
        if matched_section:
            if stripped == stripped.upper():
                confidence = min(1.0, confidence + 0.10)
            if stripped.endswith(':'):
                confidence = min(1.0, confidence + 0.08)
            if i > 0 and not lines[i-1].strip():
                confidence = min(1.0, confidence + 0.12)

            if confidence >= 0.65:
                detected.append({
                    'line_number': i,
                    'text': stripped,
                    'section': matched_section,
                    'confidence': round(confidence, 2)
                })

    return detected
